class Solution {
    private static final int MOD = (int) (1e9 + 7);
    private int[][] memo;

    public int countKReducibleNumbers(String s, int k) {
        int n = s.length();
        memo = new int[n + 1][1 << (k + 1)];
        for (int[] row : memo) {
            Arrays.fill(row, -1);
        }
        int num = Integer.parseInt(s, 2);
        return dfs(s, k, 0, 0, true);
    }

    private int dfs(String s, int k, int index, int count, boolean isLimit) {
        if (index == s.length()) {
            return countK(count, k);
        }
        if (!isLimit && memo[index][count] != -1) {
            return memo[index][count];
        }
        int res = 0;
        int up = isLimit ? s.charAt(index) - '0' : 1;
        for (int d = 0; d <= up; d++) {
            res = (res + dfs(s, k, index + 1, count + d, isLimit && d == up)) % MOD;
        }
        if (!isLimit) {
            memo[index][count] = res;
        }
        return res;
    }

    private int countK(int x, int k) {
        for (int i = 0; i < k; i++) {
            x = Integer.bitCount(x);
            if (x == 1) {
                return 1;
            }
        }
        return x == 1 ? 1 : 0;
    }
}
